#include <bits/stdc++.h>
using namespace std;
#define l first
#define f second
#define int long long
const int maxn=1e5+5,mod=1e9+7;
int n,a[maxn],dp[maxn],ans;
int stk[maxn],top;
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	while(cin>>a[++n]);
	n--;
	for(int i=1;i<=n;i++){
		int pos=upper_bound(stk+1,stk+1+top,a[i],greater<int>())-stk;
		if(pos==top+1){
			top++;
		}
		stk[pos]=a[i];
		ans=max(ans,pos);
	}
	cout<<ans<<"\n";
	ans=-1;
	top=0;
	fill(stk,stk+n+5,0);
	for(int i=1;i<=n;i++){
		int pos=lower_bound(stk+1,stk+1+top,a[i])-stk;
		if(pos==top+1){
			top++;
		}
		stk[pos]=a[i];
		ans=max(ans,pos);
	}
	cout<<ans;
	return 0;
}
